import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p.get('resolvedVersion', p.get('requestedVersion','?'))
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes = True
            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for proj in sorted(a.keys()):
    ap = a.get(proj, {})
    bp = b.get(proj, {})
    for pkg in sorted(ap.keys()):
        if bp.get(pkg) == ap.get(pkg):
            print(f'  {proj}: {pkg} {ap[pkg]}')
